const raw = $input.item.json.stdout || '';
try {
  const d = JSON.parse(raw);
  if (d.all_fresh) {
    return [{ json: { all_fresh: true, summary: null } }];
  }
  let msg = `📋 *Memory Freshness Alert*\n\n`;
  msg += `${d.stale.length} doc(s) are stale vs last nexus-core commit:\n\n`;
  for (const s of d.stale) {
    if (s.stale_hours === 9999) {
      msg += `✗ \`${s.file}\` — FILE MISSING\n`;
    } else if (s.error) {
      msg += `✗ \`${s.file}\` — error: ${s.error}\n`;
    } else {
      msg += `✗ \`${s.file}\` — ${s.stale_hours}h behind (last commit: ${s.last_commit})\n`;
    }
  }
  msg += `\nRun session close checklist in AGENTS.md`;
  return [{ json: { all_fresh: false, summary: msg } }];
} catch (e) {
  return [{ json: { all_fresh: false, summary: `📋 *Memory audit failed*\n\n${raw.substring(0, 300)}` } }];
}
